def get_cache_key(prefix, *args):
    """Generate a cache key from prefix and arguments"""
    key_string = f"{prefix}:{':'.join(str(arg) for arg in args)}"
    return hashlib.md5(key_string.encode()).hexdigest()

def get_cached_data(key):
    """Retrieve data from cache"""
    if memcached_client is None:
        return None
    try:
        cached_data = memcached_client.get(key)
        return cached_data
    except Exception:
        return None

def set_cached_data(key, data, ttl=300):
    """Store data in cache with TTL"""
    if memcached_client is None:
        return False
    try:
        memcached_client.set(key, data, expire=ttl)
        return True
    except Exception:
        return False

